  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id       String @id @default(uuid())\n  email    String @unique\n  username String @unique\n  password String\n  role     String @default(\"USER\")\n\n  // Perfil básico\n  bio       String?\n  bioLong   String? // Bio extendida para creadores de contenido\n  avatarUrl String?\n  bannerUrl String? // Banner/portada del perfil\n\n  // Tipo de cuenta\n  isInfluencer Boolean @default(false)\n  isVerified   Boolean @default(false)\n  accountType  String  @default(\"BASIC\") // BASIC, PRO, CREATOR, ANALYST\n\n  // Información profesional\n  title    String? // ej: \"Trading Analyst\", \"Crypto Investor\"\n  company  String?\n  location String?\n  website  String?\n\n  // Redes sociales\n  linkedinUrl  String?\n  twitterUrl   String?\n  youtubeUrl   String?\n  instagramUrl String?\n\n  // Experiencia y credenciales\n  yearsExperience Int?\n  specializations String? // JSON array: [\"Stocks\", \"Crypto\", \"Options\"]\n  certifications  String? // JSON array de certificaciones\n\n  // Estadísticas públicas\n  totalReturn Float? // Retorno total del portfolio (si es público)\n  winRate     Float? // Tasa de éxito en trades\n  riskScore   Float? // Score de riesgo (1-10)\n\n  // Configuración de privacidad\n  isProfilePublic    Boolean @default(true)\n  showPortfolio      Boolean @default(false)\n  showStats          Boolean @default(false)\n  acceptingFollowers Boolean @default(true)\n\n  // Relaciones\n  posts      Post[]\n  comments   Comment[]\n  likes      Like[]\n  followedBy Follow[]  @relation(\"following\")\n  following  Follow[]  @relation(\"follower\")\n\n  portfolios Portfolio[]\n  watchlists Watchlist[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Follow {\n  followerId  String\n  followingId String\n  follower    User   @relation(\"follower\", fields: [followerId], references: [id])\n  following   User   @relation(\"following\", fields: [followingId], references: [id])\n\n  @@id([followerId, followingId])\n}\n\nmodel Post {\n  id       String  @id @default(uuid())\n  content  String\n  mediaUrl String?\n  authorId String\n  author   User    @relation(fields: [authorId], references: [id])\n\n  likes    Like[]\n  comments Comment[]\n\n  tickers String // Comma separated tickers\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Comment {\n  id       String @id @default(uuid())\n  content  String\n  postId   String\n  post     Post   @relation(fields: [postId], references: [id])\n  authorId String\n  author   User   @relation(fields: [authorId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel Like {\n  postId String\n  userId String\n  post   Post   @relation(fields: [postId], references: [id])\n  user   User   @relation(fields: [userId], references: [id])\n\n  @@id([postId, userId])\n}\n\nmodel Portfolio {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  nombre             String\n  descripcion        String?\n  objetivo           String?\n  monedaBase         String  @default(\"USD\")\n  nivelRiesgo        String  @default(\"medio\")\n  modoSocial         Boolean @default(false)\n  esPrincipal        Boolean @default(false)\n  admiteBienesRaices Boolean @default(false)\n\n  // Relations\n  holdings     Holding[]\n  transactions Transaction[]\n  cashAccounts CashAccount[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Asset {\n  id       String @id @default(uuid())\n  ticker   String @unique\n  name     String\n  type     String // STOCK, CRYPTO, ETF, BOND\n  currency String @default(\"USD\")\n\n  holdings     Holding[]\n  transactions Transaction[]\n}\n\nmodel Holding {\n  id          String @id @default(uuid())\n  portfolioId String\n  assetId     String\n\n  quantity    Decimal @default(0)\n  averageCost Decimal @default(0) // WAC\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id], onDelete: Cascade)\n  asset     Asset     @relation(fields: [assetId], references: [id])\n\n  @@unique([portfolioId, assetId])\n}\n\nmodel Transaction {\n  id          String  @id @default(uuid())\n  portfolioId String\n  assetId     String? // Null for DEPOSIT/WITHDRAW\n\n  type String // BUY, SELL, DIVIDEND, FEE, DEPOSIT, WITHDRAW\n  date DateTime @default(now())\n\n  quantity     Decimal @default(0)\n  pricePerUnit Decimal @default(0)\n  fee          Decimal @default(0)\n  total        Decimal @default(0)\n  currency     String  @default(\"USD\")\n\n  notes String?\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id], onDelete: Cascade)\n  asset     Asset?    @relation(fields: [assetId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel CashAccount {\n  id          String  @id @default(uuid())\n  portfolioId String\n  currency    String\n  balance     Decimal @default(0)\n\n  portfolio Portfolio @relation(fields: [portfolioId], references: [id], onDelete: Cascade)\n\n  @@unique([portfolioId, currency])\n}\n\nmodel Watchlist {\n  id      String @id @default(uuid())\n  name    String\n  userId  String\n  user    User   @relation(fields: [userId], references: [id])\n  tickers String\n\n  createdAt DateTime @default(now())\n}\n\n// ============================================\n// NEWS SYSTEM MODELS\n// ============================================\n\nmodel NewsSource {\n  id       String  @id @default(uuid())\n  name     String  @unique\n  apiType  String // 'rss', 'api', 'scraper'\n  country  String // 'AR', 'US', 'GLOBAL'\n  language String  @default(\"es\")\n  isActive Boolean @default(true)\n  priority Int     @default(0) // Higher = more important\n\n  news News[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel NewsCategory {\n  id          String  @id @default(uuid())\n  name        String  @unique\n  slug        String  @unique\n  description String?\n  color       String? // For UI display\n  icon        String? // Icon identifier\n\n  news News[]\n\n  createdAt DateTime @default(now())\n}\n\nmodel News {\n  id String @id @default(uuid())\n\n  // Content\n  title     String\n  titleEs   String? // Spanish translation if original is English\n  content   String // Full article content\n  contentEs String? // Spanish translation\n  summary   String // Short summary\n  summaryEs String?\n\n  // Metadata\n  url           String  @unique\n  urlHash       String  @unique // MD5 hash to prevent duplicates\n  imageUrl      String?\n  language      String  @default(\"es\") // Original language\n  wasTranslated Boolean @default(false)\n\n  // Classification\n  categoryId String?\n  category   NewsCategory? @relation(fields: [categoryId], references: [id])\n\n  sourceId String\n  source   NewsSource @relation(fields: [sourceId], references: [id])\n\n  author String?\n\n  // Analysis\n  sentiment      String? // 'positive', 'neutral', 'negative'\n  sentimentScore Float? // -1.0 to 1.0\n  impactLevel    String? // 'high', 'medium', 'low'\n\n  // Associated companies/tickers\n  tickers String @default(\"\") // Comma-separated tickers\n\n  // Engagement\n  viewCount Int @default(0)\n\n  // Dates\n  publishedAt DateTime\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([publishedAt])\n  @@index([categoryId])\n  @@index([sourceId])\n  @@index([sentiment])\n}\n",
